B.aax=s(["Era tu destino...","Nos vemos en el inframundo..."],t.s)
B.aeC=s(["Hmph... Solo esta vez.","La muerte... Nunca pierde. Volver\xe9."],t.s)
B.a4p=s(["...\xa1Mi bot\xedn!","\xa1Insecto mortal!"],t.s)
B.a40=s(["\xa1Ugh...! \xa1Burl\xe1ndote de la Parca!","\xa1El m\xe1s all\xe1 tiembla...!"],t.s)
B.aaP=s(["Hmph, acortando tu propia vida.","Pasos hacia la muerte..."],t.s)
B.a5M=s(["\xa1E-esto no est\xe1 en el registro de la Parca!","\xbf\xa1Intentando cosecharme a m\xed?!","L-locura total..."],t.s)
B.a1t=s(["Mi l\xe1mpara de vida parpadea...","Maldito demonio..."],t.s)
B.a9x=s(["...Hmph, vida de rata.","Suplicando por tu vida con solo eso."],t.s)
B.aal=s(["...\xbfLeyendo el destino?","Ojos agudos."],t.s)
B.a4d=s(["...\xbfNo puedes ver la sombra de la muerte?","Insensato."],t.s)
B.aif=new A.P(B.x,[B.TW,B.abF,B.a7I,B.W8,B.aeU,B.aax,B.aeC,B.a4p,B.a40,B.aaP,B.a5M,B.a1t,B.a9x,B.aal,B.a4d],t.M)
B.a5Z=s(["Ya lo vi...","Como fue profetizado...","La luz estelar lo alcanz\xf3."],t.s)
B.a14=s(["El futuro... est\xe1 temblando.","Esto tambi\xe9n es destino...","Las estrellas est\xe1n ocultas por nubes."],t.s)
B.XT=s(["\xa1\xa1\xa1La ira del or\xe1culo!!!","\xa1Bomba del destino!"],t.s)
B.S1=s(["El or\xe1culo dice... \xa1Go!","A\xfan no es el final, las estrellas lo quieren."],t.s)
B.a4s=s(["Las estrellas me dicen que pare.","Tu destino termina aqu\xed... por ahora."],t.s)
B.SO=s(["Exactamente como fue profetizado~","La voluntad de las estrellas."],t.s)
B.a8T=s(["\xbf\xa1El futuro... cambi\xf3?!","\xa1Esto no puede ser...! \xa1Un resultado que no est\xe1 en el libro de profec\xedas!"],t.s)
B.a2f=s(["\xa1Ah! \xa1Los engranajes del destino...!","\xa1Mi velo de luz estelar fue levantado!"],t.s)
B.Vz=s(["\xa1\xa1Kyaaak!! \xa1La profec\xeda fall\xf3!","\xa1Un choque masivo de destinos...!"],t.s)
B.a8y=s(["Pretendes forjar tu propio futuro...","Las estrellas est\xe1n observando."],t.s)
B.Vo=s(["\xa1E-esto va m\xe1s all\xe1 de la profec\xeda...!","\xa1El hilo del destino se rompi\xf3...!","Una ruina aterradora se acerca..."],t.s)
B.Xv=s(["Mi poder divino... se desvanece...","\xa1La profec\xeda de cat\xe1strofe era cierta!"],t.s)
B.a2U=s(["Parece que solo robaste un poco de destino.","Las estrellas est\xe1n aliviadas."],t.s)
B.Mn=s(["\xbfEspiaste el futuro?","Excelente intuici\xf3n."],t.s)
B.P6=s(["El destino no se ve tan f\xe1cilmente~","La luz estelar se burla de ti."],t.s)
B.ahT=new A.P(B.x,[B.a5Z,B.a14,B.XT,B.S1,B.a4s,B.SO,B.a8T,B.a2f,B.Vz,B.a8y,B.Vo,B.Xv,B.a2U,B.Mn,B.P6],t.M)
B.a33=s(["\xa1Jajaja! \xa1Por supuesto!","\xa1El toque de un dios!","\xa1El universo me ayuda!"],t.s)
B.PX=s(["Hmph... Fall\xe9 por diversi\xf3n.","...","Piedad para un mortal."],t.s)
B.aed=s(["\xa1\xa1\xa1Castigo divino!!!","\xa1\xa1\xa1El universo explota!!! \xa1Autoridad divina!"],t.s)
B.Ry=s(["\xa1\xa1\xa1Go!!! \xa1El dios nunca se detiene!","\xa1Victoria sin fin! \xa1Infinito!"],t.s)
B.a2x=s(["Es suficiente... Por hoy.","\xa1Te conceder\xe9 piedad. Stop!"],t.s)
B.OW=s(["\xa1Jajaja! \xbf\xa1Desafiar a un dios?!","\xa1Un resultado natural! \xa1La providencia del universo!"],t.s)
B.Zj=s(["Esto... \xa1\xa1Imposible...!!","\xbf\xa1Qui\xe9n... qui\xe9n eres?! \xbf\xa1Un bug?!"],t.s)
B.S8=s(["\xa1Ugh! \xa1Tomando el milagro de un dios!","\xa1\xa1Buuuuug!!"],t.s)
B.a9D=s(["\xa1\xa1Los cielos se derrumban!!","\xa1\xa1\xa1B-bug!!! \xa1Burl\xe1ndose de un dios!"],t.s)
B.WN=s(["Ho-oh~ \xa1Luchas bastante bien!","\xbfProbando la paciencia de un dios?"],t.s)
B.XI=s(["E-esto es capacidad humana...","\xa1M-mi c\xf3digo se enreda!!","\xa1Por favor perd\xf3name! \xa1\xa1\xa1Me degradar\xe1n de la divinidad!!!"],t.s)
B.OP=s(["El reino divino est\xe1 en bancarrota...","\xbf\xa1Usaste un truco, verdad?! \xa1\xa1Te banear\xe9!!"],t.s)
B.a7A=s(["\xa1Jaja! \xa1Intentando vencer a un dios con solo eso!","\xa1Una victoria trivial!"],t.s)
B.UT=s(["...\xbfDestino retorcido?","Un mono bastante inteligente."],t.s)
B.a2k=s(["\xa1Jajaja! \xa1El l\xedmite de un mortal!","\xa1Ca\xedste en mi cortina de humo divina!"],t.s)
B.a6G=s(["\xa1Jajaja! \xa1Pat\xe9tico no tener Gwang! \xa1Mortal!"],t.s)
